mapper.select:

SELECT COUNT(*)
FROM likes
WHERE user_id = #{userId}


SELECT COUNT(*)
FROM reviews
WHERE user_id = #{userId}
    AND YEAR(created_at) = #{year}
  AND MONTH(created_at) = #{month}
  AND status = TRUE
  AND temporary = FALSE


SELECT COALESCE(AVG(cnt), 0.0)
FROM (
         SELECT COUNT(*) AS cnt
         FROM reviews
         WHERE YEAR(created_at) = #{year}
           AND MONTH(created_at) = #{month}
           AND status = TRUE
           AND temporary = FALSE
         GROUP BY user_id
     ) AS user_counts
